18	// does in production. sessionID is distinct per call so a test can prove the fan-out mints
19	// genuinely per-peer probers (not shared handles), though the load-bearing per-peer distinction
20	// is the psk.
21	func concPeerWiring(t testing.TB, paths []config.Path, psk config.Key, sessionID uint64, clk telemetry.Clock) (sched.Scheduler, []*telemetry.Prober, ProberFactory) {
22		t.Helper()
23		lg, err := log.New("error", io.Discard)
24		if err != nil {
25			t.Fatalf("build logger: %v", err)
26		}
27		cfg := telemetry.ProberConfig{
28			LossWindow: 0,
29			Liveness:   telemetry.LivenessConfig{DownAfter: testProbeDownAfter, UpAfterSuccesses: testProbeUpSucc},
30		}
31		newProber := func(name string, id uint8) *telemetry.Prober {
32			return telemetry.NewProber(name, id, sessionID, psk, cfg, clk, lg)
33		}
34		probers := make([]*telemetry.Prober, len(paths))
35		health := make([]sched.PathHealth, len(paths))
36		for i := range paths {
37			probers[i] = newProber(paths[i].Name, uint8(i))
38			health[i] = probers[i]
39		}
40		scheduler, err := sched.NewActiveBackup(health, sched.Config{FailbackAfter: time.Hour}, clk, lg)
