package bind

import (
	"net"
	"net/netip"
	"syscall"
	"testing"

	"github.com/7mind/wanbond/internal/config"
)

// REVIEW REPRO (T93): a DEFERRED runtime AddPath on a 2-peer concentrator grows m.defs and
// the PRIMARY's probers only; the next Close->Open that successfully binds that def indexes
// beta.probers[i] out of range.
func TestReproDeferredAddPathThenReopenTwoPeers(t *testing.T) {
	pskA := testKey(t, 0x77)
	pskB := testKey(t, 0x88)
	clk := newFakeClock()
	paths := loopbackPaths(1)
	m, _, _ := newProbingMultipath(t, paths, pskA, clk)

	bs, bp, bf := concPeerWiring(t, paths, pskB, 0xD00D, clk)
	if err := m.AddConcentratorPeer("beta", pskB, bs, bp, bf); err != nil {
		t.Fatalf("AddConcentratorPeer: %v", err)
	}
	if _, _, err := m.Open(0); err != nil {
		t.Fatalf("Open: %v", err)
	}

	// Force the runtime add to DEFER (source addr not yet assignable).
	real := m.addPathListen
	m.addPathListen = func(src netip.Addr, port uint16, dev string) (*net.UDPConn, error) {
		return nil, syscall.EADDRNOTAVAIL
	}
	if err := m.AddPath(config.Path{Name: "deferred-x", SourceAddr: netip.MustParseAddr("127.0.0.1")}); err != nil {
		t.Fatalf("AddPath (deferred): %v", err)
	}
	m.addPathListen = real

	if err := m.Close(); err != nil {
		t.Fatalf("Close: %v", err)
	}
	// Reopen: the deferred def's 127.0.0.1 IS assignable now, so Open binds it and
	// builds every peer's view -> beta.probers[1] with len(beta.probers)==1.
	if _, _, err := m.Open(0); err != nil {
		t.Fatalf("reopen: %v", err)
	}
	_ = m.Close()
}
EOF
